+    fn apply_visual_selection(&self, buffer: &mut Buffer, visible_right_content: &str) {
+        let Some(selection) = &self.visual_selection else {
+            return;
+        };
+        let Some(rect) = self.pane_inner_rect(selection.pane) else {
+            return;
+        };
+        let lines = self.pane_lines_for_render(selection.pane, visible_right_content);
+        for (row, start, end) in selection_ranges(selection, &lines) {
+            self.apply_visual_range(buffer, rect, selection.pane, &lines, row, start, end);
+        }
+    }
+
+    fn pane_inner_rect(&self, pane: PaneFocus) -> Option<Rect> {
+        let layout = self.layout();
+        let body_height = self.height.saturating_sub(1);
+        if body_height <= 2 {
+            return None;
+        }
+        match pane {
+            PaneFocus::Left if self.left_visible && layout.left_width > 2 => {
+                Some(Rect::new(1, 1, layout.left_width - 2, body_height - 2))
+            }
+            PaneFocus::Right if layout.right_width > 2 => {
+                let pane_x = if self.left_visible {
+                    layout.left_width
+                } else {
+                    0
+                };
+                Some(Rect::new(
+                    pane_x.saturating_add(1),
+                    1,
+                    layout.right_width - 2,
+                    body_height - 2,
+                ))
+            }
+            _ => None,
+        }
+    }
+
+    fn apply_visual_range(
+        &self,
+        buffer: &mut Buffer,
+        rect: Rect,
+        pane: PaneFocus,
+        lines: &[String],
+        row: usize,
+        start: usize,
+        end: usize,
+    ) {
+        match pane {
+            PaneFocus::Left => {
+                let y = rect.y.saturating_add(row.min(usize::from(u16::MAX)) as u16);
+                let render_end = end.max(start.saturating_add(1));
+                self.apply_reversed_cells(buffer, rect, y, start, render_end);
+            }
+            PaneFocus::Right => {
+                let base_row = lines
+                    .iter()
+                    .take(row)
+                    .map(|line| visual_row_count(line, rect.width))
+                    .sum::<usize>();
+                let render_end = end.max(start.saturating_add(1));
+                let width = usize::from(rect.width.max(1));
+                let first_segment = start / width;
+                let last_segment = render_end.saturating_sub(1) / width;
+                for segment in first_segment..=last_segment {
+                    let y = rect
+                        .y
+                        .saturating_add((base_row + segment).min(usize::from(u16::MAX)) as u16);
+                    let segment_start = if segment == first_segment {
+                        start % width
+                    } else {
+                        0
+                    };
+                    let segment_end = if segment == last_segment {
+                        render_end.saturating_sub(segment * width)
+                    } else {
+                        width
+                    };
+                    self.apply_reversed_cells(buffer, rect, y, segment_start, segment_end);
+                }
+            }
+        }
+    }
+
+    fn apply_reversed_cells(
+        &self,
+        buffer: &mut Buffer,
+        rect: Rect,
+        y: u16,
+        start: usize,
+        end: usize,
+    ) {
+        if y < rect.y || y >= rect.y.saturating_add(rect.height) {
+            return;
+        }
+        let start = start.min(usize::from(rect.width));
+        let end = end.min(usize::from(rect.width));
+        for offset in start..end {
+            let x = rect
+                .x
+                .saturating_add(offset.min(usize::from(u16::MAX)) as u16);
+            buffer
+                .get_mut(x, y)
+                .set_style(Style::default().add_modifier(Modifier::REVERSED));
+        }
+    }
