+    fn handle_visual_key(&mut self, key: UiKey, right_content: &str) -> Vec<UiAction> {
+        match key {
+            UiKey::Esc => {
+                self.clear_visual_selection();
+                self.mode = UiMode::Command;
+            }
+            UiKey::Char('y') => self.copy_visual_selection(right_content, false),
+            UiKey::Char('Y') => self.copy_visual_selection(right_content, true),
+            UiKey::Char('v') => self.set_visual_kind(VisualKind::Character),
+            UiKey::Char('V') => self.set_visual_kind(VisualKind::Line),
+            UiKey::Char(CTRL_V_CHAR) => self.set_visual_kind(VisualKind::Block),
+            UiKey::Char('h') | UiKey::Left => self.move_visual_head(0, -1, right_content),
+            UiKey::Char('l') | UiKey::Right => self.move_visual_head(0, 1, right_content),
+            UiKey::Char('j') | UiKey::Down => self.move_visual_head(1, 0, right_content),
+            UiKey::Char('k') | UiKey::Up => self.move_visual_head(-1, 0, right_content),
+            _ => {}
+        }
+        Vec::new()
+    }
+
+    fn start_visual_selection(
+        &mut self,
+        kind: VisualKind,
+        right_content: &str,
+        right_cursor_column: Option<usize>,
+    ) {
+        let pane = if self.focus == PaneFocus::Left && !self.left_visible {
+            PaneFocus::Right
+        } else {
+            self.focus
+        };
+        let lines = self.pane_lines_for_key(pane, right_content);
+        if lines.is_empty() {
+            return;
+        }
+        let position = self.current_visual_position(pane, &lines, right_cursor_column);
+        self.visual_selection = Some(VisualSelection {
+            pane,
+            kind,
+            anchor: position,
+            head: position,
+        });
+        self.mode = UiMode::Command;
+    }
+
+    fn set_visual_kind(&mut self, kind: VisualKind) {
+        if let Some(selection) = self.visual_selection.as_mut() {
+            selection.kind = kind;
+        }
+    }
+
+    fn move_visual_head(&mut self, row_delta: isize, column_delta: isize, right_content: &str) {
+        let Some(mut selection) = self.visual_selection.take() else {
+            return;
+        };
+        let lines = self.pane_lines_for_key(selection.pane, right_content);
+        if lines.is_empty() {
+            self.visual_selection = Some(selection);
+            return;
+        }
+
+        if selection.kind != VisualKind::Line {
+            let next_column = selection.head.column as isize + column_delta;
+            let max_column = selectable_column(&lines[selection.head.row.min(lines.len() - 1)]);
+            selection.head.column = next_column.clamp(0, max_column as isize) as usize;
+        }
+
+        let next_row = selection.head.row as isize + row_delta;
+        selection.head.row = next_row.clamp(0, (lines.len() - 1) as isize) as usize;
+        let max_column = selectable_column(&lines[selection.head.row]);
+        selection.head.column = selection.head.column.min(max_column);
+        self.visual_selection = Some(selection);
+    }
+
+    fn copy_visual_selection(&mut self, right_content: &str, force_linewise: bool) {
+        let Some(selection) = self.visual_selection.clone() else {
+            return;
+        };
+        let lines = self.pane_lines_for_key(selection.pane, right_content);
+        let selection = if force_linewise {
+            VisualSelection {
+                kind: VisualKind::Line,
+                ..selection
+            }
+        } else {
+            selection
+        };
+        let text = selected_text(&selection, &lines);
+        self.finish_copy(text);
+    }
+
+    fn copy_current_line(&mut self, right_content: &str, right_cursor_column: Option<usize>) {
+        let pane = if self.focus == PaneFocus::Left && !self.left_visible {
+            PaneFocus::Right
+        } else {
+            self.focus
+        };
+        let lines = self.pane_lines_for_key(pane, right_content);
+        if lines.is_empty() {
+            return;
+        }
+        let position = self.current_visual_position(pane, &lines, right_cursor_column);
+        let text = lines.get(position.row).cloned().unwrap_or_default();
+        self.finish_copy(text);
+    }
+
+    fn finish_copy(&mut self, text: String) {
+        self.clear_visual_selection();
+        self.mode = UiMode::Command;
+        self.copied_text.replace(Some(text.clone()));
+        self.pending_clipboard.replace(Some(text.clone()));
+        self.show_status_notice(copied_status_text(&text), Duration::from_secs(STATUS_NOTICE_SECONDS));
+    }
+
+    fn current_visual_position(
+        &self,
+        pane: PaneFocus,
+        lines: &[String],
+        right_cursor_column: Option<usize>,
+    ) -> TextPosition {
+        let row = match pane {
+            PaneFocus::Left => self.control_selected.min(lines.len().saturating_sub(1)),
+            PaneFocus::Right => lines.len().saturating_sub(1),
+        };
+        let column = match pane {
+            PaneFocus::Left => 0,
+            PaneFocus::Right => right_cursor_column
+                .unwrap_or_else(|| line_char_count(&lines[row]))
+                .saturating_sub(1),
+        }
+        .min(selectable_column(&lines[row]));
+        TextPosition { row, column }
+    }
+
+    fn pane_lines_for_key(&self, pane: PaneFocus, right_content: &str) -> Vec<String> {
+        match pane {
+            PaneFocus::Left => self.left_pane_lines(),
+            PaneFocus::Right => split_text_lines(&self.visible_right_content(right_content)),
