@@
 fn truncate_to_width(text: &str, width: usize) -> String {
     text.chars().take(width).collect()
 }
+
+fn split_text_lines(text: &str) -> Vec<String> {
+    if text.is_empty() {
+        vec![String::new()]
+    } else {
+        text.split('\n').map(str::to_string).collect()
+    }
+}
+
+fn line_char_count(line: &str) -> usize {
+    line.chars().count()
+}
+
+fn selectable_column(line: &str) -> usize {
+    line_char_count(line).saturating_sub(1)
+}
+
+fn selection_ranges(
+    selection: &VisualSelection,
+    lines: &[String],
+) -> Vec<(usize, usize, usize)> {
+    if lines.is_empty() {
+        return Vec::new();
+    }
+    let anchor = clamp_text_position(selection.anchor, lines);
+    let head = clamp_text_position(selection.head, lines);
+    let start_row = anchor.row.min(head.row);
+    let end_row = anchor.row.max(head.row);
+
+    match selection.kind {
+        VisualKind::Line => (start_row..=end_row)
+            .map(|row| (row, 0, line_char_count(&lines[row])))
+            .collect(),
+        VisualKind::Block => {
+            let start_column = anchor.column.min(head.column);
+            let end_column = anchor.column.max(head.column).saturating_add(1);
+            (start_row..=end_row)
+                .map(|row| {
+                    let line_len = line_char_count(&lines[row]);
+                    (row, start_column.min(line_len), end_column.min(line_len))
+                })
+                .collect()
+        }
+        VisualKind::Character => {
+            let (start, end) = ordered_positions(anchor, head);
+            (start.row..=end.row)
+                .map(|row| {
+                    let line_len = line_char_count(&lines[row]);
+                    if start.row == end.row {
+                        (row, start.column.min(line_len), end.column.saturating_add(1).min(line_len))
+                    } else if row == start.row {
+                        (row, start.column.min(line_len), line_len)
+                    } else if row == end.row {
+                        (row, 0, end.column.saturating_add(1).min(line_len))
+                    } else {
+                        (row, 0, line_len)
+                    }
+                })
+                .collect()
+        }
+    }
+}
+
+fn selected_text(selection: &VisualSelection, lines: &[String]) -> String {
+    selection_ranges(selection, lines)
+        .into_iter()
+        .map(|(row, start, end)| char_range(&lines[row], start, end))
+        .collect::<Vec<_>>()
+        .join("\n")
+}
+
+fn char_range(line: &str, start: usize, end: usize) -> String {
+    line.chars()
+        .skip(start)
+        .take(end.saturating_sub(start))
+        .collect()
+}
+
+fn clamp_text_position(position: TextPosition, lines: &[String]) -> TextPosition {
+    let row = position.row.min(lines.len().saturating_sub(1));
+    TextPosition {
+        row,
+        column: position.column.min(selectable_column(&lines[row])),
+    }
+}
+
+fn ordered_positions(left: TextPosition, right: TextPosition) -> (TextPosition, TextPosition) {
+    if (left.row, left.column) <= (right.row, right.column) {
+        (left, right)
+    } else {
+        (right, left)
+    }
+}
+
+fn copied_status_text(text: &str) -> String {
+    let count = text.chars().count();
+    let suffix = if count == 1 { "" } else { "s" };
+    format!("copied {count} character{suffix}")
+}
