+fn base64_encode(bytes: &[u8]) -> String {
+    const TABLE: &[u8; 64] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
+    let mut encoded = String::new();
+    let mut index = 0;
+    while index < bytes.len() {
+        let first = bytes[index];
+        let second = bytes.get(index + 1).copied();
+        let third = bytes.get(index + 2).copied();
+
+        encoded.push(TABLE[usize::from(first >> 2)] as char);
+        encoded.push(TABLE[usize::from(((first & 0b0000_0011) << 4) | (second.unwrap_or(0) >> 4))] as char);
+        if let Some(second) = second {
+            encoded.push(TABLE[usize::from(((second & 0b0000_1111) << 2) | (third.unwrap_or(0) >> 6))] as char);
+        } else {
+            encoded.push('=');
+        }
+        if let Some(third) = third {
+            encoded.push(TABLE[usize::from(third & 0b0011_1111)] as char);
+        } else {
+            encoded.push('=');
+        }
+        index += 3;
+    }
+    encoded
